SELECT COUNT(*)
FROM meetings m
WHERE m.meetingId = #{meetingId}
  AND m.deletedAt IS NULL
  AND (
    m.hostUserId = #{userId}
    OR EXISTS (
        SELECT 1
        FROM meetingParticipants mp
        WHERE mp.meetingId = m.meetingId
          AND mp.userId = #{userId}
          AND mp.status = 'APPROVED'
          AND mp.chatLeftAt IS NULL
    )
  )

SELECT title
FROM meetings
WHERE meetingId = #{meetingId}

SELECT DISTINCT target.userId
FROM (
    SELECT m.hostUserId AS userId
    FROM meetings m
    WHERE m.meetingId = #{meetingId}
    UNION
    SELECT mp.userId
    FROM meetingParticipants mp
    WHERE mp.meetingId = #{meetingId}
      AND mp.status = 'APPROVED'
      AND mp.chatLeftAt IS NULL
) target
WHERE target.userId != #{senderUserId}

mapper.update:
UPDATE meetingParticipants
SET chatLeftAt = NOW()
WHERE meetingId = #{meetingId}
  AND userId = #{userId}
  AND status = 'APPROVED'
  AND chatLeftAt IS NULL
